import React from "react";
import "./nav.css";

function Nav() {
  const [open, setOpen] = React.useState(false);
  let style = function Modal() {
    if (!setOpen) {
      return <div className="pushMenu"></div>;
    } else {
      return <div className="pushMenu"></div>;
    }
  };
  return (
    <div
      style={{
        backgroundColor: isActive ? "salmon" : "",
        color: isActive ? "white" : "",
      }}
      onClick={Modal}
      className="gg-menu-grid-o"
    ></div>
  );
}

export default Nav;

